+const runtime = globalThis as any;
+
+async function pathApi() {
+  if (runtime.Deno) {
+    return {
+      cwd: () => runtime.Deno.cwd(),
+      resolve: (path: string) => path.startsWith("/") ? path : `${runtime.Deno.cwd()}/${path}`,
+      exists: async (path: string) => {
+        try { await runtime.Deno.stat(path); return true; } catch { return false; }
+      },
+      read: (path: string) => runtime.Deno.readTextFile(path),
+    };
+  }
+  const fs = await import("node:fs/promises");
+  const path = await import("node:path");
+  return {
+    cwd: () => process.cwd(),
+    resolve: (input: string) => path.resolve(input),
+    exists: async (input: string) => {
+      try { await fs.access(input); return true; } catch { return false; }
+    },
+    read: (input: string) => fs.readFile(input, "utf8"),
+  };
+}
+
+function camelCase(value: string): string {
+  return value.replace(/-([a-zA-Z0-9])/g, (_, char) => char.toUpperCase());
+}
+
+function flatten(value: Record<string, unknown>, prefix = ""): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+  for (const [key, item] of Object.entries(value)) {
+    const name = prefix ? `${prefix}.${camelCase(key)}` : camelCase(key);
+    if (item && typeof item === "object" && !Array.isArray(item)) {
+      Object.assign(result, flatten(item as Record<string, unknown>, name));
+    } else {
+      result[name] = item;
+    }
+  }
+  return result;
+}
+
+export function parseRc(content: string): Record<string, unknown> {
+  const values: Record<string, unknown> = {};
+  for (const line of content.split(/\\r?\
/)) {
+    const trimmed = line.trim();
+    if (!trimmed || trimmed.startsWith("#")) continue;
+    const index = trimmed.indexOf("=");
+    if (index < 0) continue;
+    const key = camelCase(trimmed.slice(0, index).trim());
+    let value = trimmed.slice(index + 1).trim();
+    if (value.length >= 2 && value.startsWith('"') && value.endsWith('"')) {
+      value = value.slice(1, -1);
+    } else if (value === "true" || value === "false") {
+      values[key] = value === "true";
+      continue;
+    } else if (/^-?(?:\\d+\\.?\\d*|\\.\\d+)$/.test(value)) {
+      values[key] = Number(value);
+      continue;
+    }
+    values[key] = value;
+  }
+  return values;
+}
+
+function parse(content: string, format: string, options: ConfigOptions): Record<string, unknown> {
+  if (options.parser) return options.parser(content);
+  if (format === ".rc") return parseRc(content);
+  return JSON.parse(content) as Record<string, unknown>;
+}
+
+export async function loadConfig(options: ConfigOptions): Promise<LoadedConfig> {
+  const api = await pathApi();
+  const searchPaths = options.searchPaths ?? [api.cwd()];
+  const formats = options.formats ?? [".json", ".rc"];
+  const found: Array<{ path: string; format: string }> = [];
+  for (const searchPath of searchPaths) {
+    for (const format of formats) {
+      const filename = format === ".rc" ? `.${options.name}rc` : `${options.name}${format}`;
+      const file = api.resolve(`${searchPath}/${filename}`);
+      if (await api.exists(file)) {
+        found.push({ path: file, format });
+        break;
+      }
+    }
+    if (found.length && !options.mergeConfigs) break;
+  }
+  if (!found.length) return { values: {} };
+
+  const values: Record<string, unknown> = {};
+  // Earlier paths take precedence, so only fill keys which have not been set.
+  for (const file of found) {
+    try {
+      const parsed = parse(await api.read(file.path), file.format, options);
+      if (!parsed || typeof parsed !== "object" || Array.isArray(parsed)) throw new TypeError("Config must be a plain object.");
+      for (const [key, value] of Object.entries(flatten(parsed))) {
+        if (!(key in values)) values[key] = value;
+      }
+    } catch (error) {
+      throw new ConfigParseError(file.path, error);
+    }
+  }
+  return { path: found[0].path, values };
+}
