+import { test } from "@cliffy/internal/testing/test";
+import { assertEquals, assertInstanceOf, assertRejects } from "@std/assert";
+import { Command } from "../../command.ts";
+import { ConfigParseError, ConfigValidationError } from "../../config/mod.ts";
+
+async function configDir(files: Record<string, string>): Promise<string> {
+  const directory = await Deno.makeTempDir();
+  await Promise.all(Object.entries(files).map(([name, content]) => Deno.writeTextFile(`${directory}/${name}`, content)));
+  return directory;
+}
+
+test("[command] - config - loads JSON, flattens keys, and honors precedence", async () => {
+  const directory = await configDir({
+    "app.json": JSON.stringify({ "port-number": 3000, nested: { "log-level": "info" }, tags: ["one", "two"], unused: true }),
+  });
+  const command = new Command().throwErrors()
+    .config({ name: "app", searchPaths: [directory] })
+    .env("PORT_NUMBER=<value:number>", "...")
+    .option("--port-number <value:number>", "...")
+    .option("--nested.log-level <value:string>", "...")
+    .option("--tags <value:string>", "...", { collect: true });
+  const result = await command.parse(["--port-number", "5000"]);
+  assertEquals(result.options, { portNumber: 5000, nested: { logLevel: "info" }, tags: ["one", "two"] });
+  assertEquals(command.getConfigValues(), { portNumber: 3000, "nested.logLevel": "info", tags: ["one", "two"], unused: true });
+  assertEquals(command.getConfigPath(), `${directory}/app.json`);
+});
+
+test("[command] - config - supports RC files and ordered merges", async () => {
+  const first = await configDir({ ".apprc": "# comment\
enabled=true\
port=0\
title=\\"two words\\"\
" });
+  const second = await configDir({ ".apprc": "enabled=false\
port=42\
" });
+  const command = new Command().throwErrors()
+    .config({ name: "app", searchPaths: [first, second], mergeConfigs: true })
+    .option("--enabled", "...")
+    .option("--port <value:number>", "...")
+    .option("--title <value:string>", "...");
+  const { options } = await command.parse([]);
+  assertEquals(options, { enabled: true, port: 0, title: "two words" });
+});
+
+test("[command] - config - reports parse and validation errors", async () => {
+  const malformed = await configDir({ "app.json": "{" });
+  await assertRejects(
+    () => new Command().throwErrors().config({ name: "app", searchPaths: [malformed] }).parse([]),
+    ConfigParseError,
+  );
+  const invalid = await configDir({ "app.json": JSON.stringify({ port: "wrong" }) });
+  const error = await assertRejects(
+    () => new Command().throwErrors().config({ name: "app", searchPaths: [invalid] }).option("--port <value:number>", "...").parse([]),
+    ConfigValidationError,
+  );
+  assertInstanceOf(error, ConfigValidationError);
+});
+
+test("[command] - config - child config overrides inherited parent values", async () => {
+  const parentDirectory = await configDir({ "parent.json": JSON.stringify({ color: "blue" }) });
+  const childDirectory = await configDir({ "child.json": JSON.stringify({ color: "red" }) });
+  const command = new Command().throwErrors()
+    .config({ name: "parent", searchPaths: [parentDirectory] })
+    .globalOption("--color <value:string>", "...")
+    .command("child")
+    .config({ name: "child", searchPaths: [childDirectory] });
+  const result = await command.parse(["child"]);
+  assertEquals(result.options, { color: "red" });
+  assertEquals(result.cmd.getConfigValues(), { color: "red" });
+});
